SELECT COUNT(*)
FROM treatment_programs
WHERE insurance_coverage = 1;

SELECT admin_user_id, name 
FROM admin_users 
WHERE status = 'active';

SELECT AVG((julianday('now') - julianday(start_date)) / 365.25) AS AvgYears
FROM treatments
WHERE (julianday('now') - julianday(start_date)) / 365.25 > 1;

SELECT first_name || ' ' || last_name AS full_name, age
FROM patients
WHERE patient_id IN (SELECT DISTINCT patient_id FROM treatments);
